import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import './RolePlay.css';

const CATEGORIES = ['Daily Life','Healthcare','Travel','Education','Business','Culture','Entertainment'];
const JLPT = ['N5','N4','N3','N2','N1'];
const DIFFICULTIES = ['Easy','Medium','Hard'];

export default function RolePlayAddStory() {
  const navigate = useNavigate();
  const coverRef = useRef(null);
  const bgRef = useRef(null);

  const [form, setForm] = useState({
    title: '', description: '', category: 'Daily Life',
    jlpt: 'N5', difficulty: 'Easy',
  });
  const [coverPreview, setCoverPreview] = useState(null);
  const [bgPreview, setBgPreview] = useState(null);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);

  const handleChange = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleImage = (e, setter) => {
    const file = e.target.files[0];
    if (!file) return;
    const url = URL.createObjectURL(file);
    setter(url);
  };

  const handleSave = async (publish = false) => {
    if (!form.title.trim()) { alert('Story title is required.'); return; }
    setSaving(true);
    await new Promise(r => setTimeout(r, 900)); // mock delay
    setSaving(false);
    setSaved(true);
    setTimeout(() => navigate('/roleplay/stories'), 1200);
  };

  if (saved) {
    return (
      <div className="rp-page rp-center">
        <div className="rp-success-card">
          <div className="rp-success-icon">✅</div>
          <h3>Story Saved!</h3>
          <p>Redirecting to Stories...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="rp-page">
      <div className="rp-page-header">
        <div>
          <h2 className="rp-page-title">✏️ Add Story</h2>
          <p className="rp-page-sub">Enter basic story information. Dialogue is added via Excel import.</p>
        </div>
      </div>

      <div className="rp-form-layout">
        {/* Left — form */}
        <div className="card rp-form-card">
          <div className="form-group">
            <label>Story Title *</label>
            <input
              placeholder="e.g. Restaurant Conversation"
              value={form.title}
              onChange={e => handleChange('title', e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Description</label>
            <textarea
              rows={3}
              placeholder="Brief description of the conversation scenario..."
              value={form.description}
              onChange={e => handleChange('description', e.target.value)}
              style={{ resize: 'vertical' }}
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Category</label>
              <select value={form.category} onChange={e => handleChange('category', e.target.value)}>
                {CATEGORIES.map(c => <option key={c}>{c}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>JLPT Level</label>
              <select value={form.jlpt} onChange={e => handleChange('jlpt', e.target.value)}>
                {JLPT.map(j => <option key={j}>{j}</option>)}
              </select>
            </div>
          </div>

          <div className="form-group">
            <label>Difficulty</label>
            <div className="rp-radio-row">
              {DIFFICULTIES.map(d => (
                <label key={d} className={`rp-radio-btn ${form.difficulty === d ? 'active' : ''}`}>
                  <input
                    type="radio"
                    name="difficulty"
                    value={d}
                    checked={form.difficulty === d}
                    onChange={() => handleChange('difficulty', d)}
                    style={{ display: 'none' }}
                  />
                  {d === 'Easy' ? '🟢' : d === 'Medium' ? '🟡' : '🔴'} {d}
                </label>
              ))}
            </div>
          </div>

          <div className="rp-info-banner">
            <span>💡</span>
            <span>Dialogue lines, characters, and audio are added via <strong>Excel Import</strong>. You don't need to enter them manually.</span>
          </div>
        </div>

        {/* Right — images */}
        <div className="rp-form-sidebar">
          <div className="card" style={{ marginBottom: 16 }}>
            <label style={{ marginBottom: 8, display: 'block' }}>Cover Image</label>
            <div
              className="rp-image-upload"
              onClick={() => coverRef.current.click()}
              style={{ backgroundImage: coverPreview ? `url(${coverPreview})` : undefined }}
            >
              {!coverPreview && (
                <>
                  <div className="rp-upload-icon">🖼️</div>
                  <div className="rp-upload-text">Click to upload</div>
                  <div className="rp-upload-hint">PNG, JPG up to 5MB</div>
                </>
              )}
              {coverPreview && <div className="rp-image-overlay">Change</div>}
            </div>
            <input
              ref={coverRef}
              type="file"
              accept="image/*"
              style={{ display: 'none' }}
              onChange={e => handleImage(e, setCoverPreview)}
            />
          </div>

          <div className="card">
            <label style={{ marginBottom: 8, display: 'block' }}>Background Image</label>
            <div
              className="rp-image-upload"
              onClick={() => bgRef.current.click()}
              style={{ backgroundImage: bgPreview ? `url(${bgPreview})` : undefined }}
            >
              {!bgPreview && (
                <>
                  <div className="rp-upload-icon">🌅</div>
                  <div className="rp-upload-text">Click to upload</div>
                  <div className="rp-upload-hint">Shown during gameplay</div>
                </>
              )}
              {bgPreview && <div className="rp-image-overlay">Change</div>}
            </div>
            <input
              ref={bgRef}
              type="file"
              accept="image/*"
              style={{ display: 'none' }}
              onChange={e => handleImage(e, setBgPreview)}
            />
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="rp-form-actions">
        <button className="btn btn-secondary" onClick={() => navigate('/roleplay/stories')}>
          Cancel
        </button>
        <button className="btn btn-secondary" onClick={() => handleSave(false)} disabled={saving}>
          {saving ? 'Saving…' : '💾 Save Draft'}
        </button>
        <button className="btn btn-primary" onClick={() => handleSave(true)} disabled={saving}>
          {saving ? 'Saving…' : '🚀 Publish'}
        </button>
      </div>
    </div>
  );
}
